import React from "react";
import {MenuItem, Menu, Sidebar, SubMenu} from 'react-pro-sidebar';
import './index.css';
import 'bootstrap/dist/css/bootstrap.min.css';
import {BrowserRouter as Router, Routes, Route, Link } from 'react-router-dom';

import Dashboard from './pages/Dashboard';
import Inventory from './pages/inventory';

function App() {
return (
    <Router>
      <div className="d-flex" style={{ height: '100vh' }}>
        <Sidebar>
          <Menu>
            {/* Use the 'component' prop to make MenuItems act as links */}
            <MenuItem component={<Link to="/" />}> Dashboard </MenuItem>
            <MenuItem component={<Link to="/inventory" />}> Inventory </MenuItem>
          </Menu>
        </Sidebar>

        <div className="flex-grow-1">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/inventory" element={<Inventory />} />
          </Routes>
        </div>
      </div>
    </Router>
  );
}

export default App;
